  always @ (posedge reset, posedge clock) begin                                 // Execute next step in program

    if (reset) begin                                                            // Reset
      step      = 0;
      steps    <= 0;
      stopped  <= 0;
      initialize_memory_M_9();                                                   // Initialize btree memory
      initialize_memory_T_10();                                                   // Initialize btree transaction
